import React, { useState, useEffect } from 'react';
import { Typography, Card, CardMedia, CardContent, Divider, List, ListItem, ListItemText } from '@mui/material';
import { useParams } from 'react-router-dom';
import fetchModel from '../../lib/fetchModelData';

function UserPhotos() {
  const { userId } = useParams();
  const [photos, setPhotos] = useState([]);

  useEffect(() => {
    // Gọi API lấy toàn bộ ảnh và comment của user
    fetchModel(`/photosOfUser/${userId}`)
      .then((response) => {
        setPhotos(response.data);
      })
      .catch((err) => console.log("Lỗi khi tải ảnh:", err));
  }, [userId]);

  if (photos.length === 0) return <Typography>Người dùng này chưa có ảnh nào.</Typography>;

  return (
    <div>
      <Typography variant="h5" sx={{ mb: 2 }}>Ảnh của người dùng</Typography>
      {photos.map((photo) => (
        <Card key={photo._id} sx={{ mb: 4 }}>
          {/* Hiển thị ảnh - Giả sử file ảnh nằm trong thư mục images của backend */}
          <CardMedia
            component="img"
            image={`/images/${photo.file_name}`}
            alt="User photo"
          />
          <CardContent>
            <Typography variant="caption" color="textSecondary">
              Đăng ngày: {photo.date_time}
            </Typography>

            <Typography variant="h6" sx={{ mt: 2 }}>Bình luận:</Typography>
            <Divider />

            <List>
              {photo.comments && photo.comments.map((c) => (
                <ListItem key={c._id} alignItems="flex-start">
                  <ListItemText
                    primary={
                      <Link to={`/users/${c.user._id}`}>
                        {`${c.user.first_name} ${c.user.last_name}`}
                      </Link>
                    }
                    secondary={
                      <React.Fragment>
                        <Typography component="span" variant="body2" color="textPrimary">
                          {c.comment}
                        </Typography>
                        {` — ${c.date_time}`}
                      </React.Fragment>
                    }
                  />
                </ListItem>
              ))}
            </List>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

export default UserPhotos;
